  3→import { useState, useCallback, useEffect, useRef } from "react";
  4→import { QRCodeSVG } from "qrcode.react";
  5→
  6→interface SelfVerificationProps {
  7→  walletAddress: string;
  8→  onSuccess: (agentAddress: string) => void;
  9→}
 10→
 11→interface RegistrationResponse {
 12→  sessionKey: string;
 13→  deepLink: string;
 14→  agentAddress: string;
 15→  expiresAt: string;
 16→  stage: string;
 17→  humanInstructions: string[];
 18→}
 19→
 20→export function SelfVerification({
 21→  walletAddress,
 22→  onSuccess,
 23→}: SelfVerificationProps) {
 24→  const [session, setSession] = useState<RegistrationResponse | null>(null);
 25→  const [status, setStatus] = useState<string>("idle");
 26→  const [error, setError] = useState<string | null>(null);
 27→  const pollingRef = useRef<NodeJS.Timeout | null>(null);
 28→
 29→  // Start registration
 30→  const startRegistration = useCallback(async () => {
 31→    if (!walletAddress) return;
 32→
 33→    setStatus("registering");
 34→    setError(null);
 35→
 36→    try {
 37→      const res = await fetch("/api/agent-id/register", {
 38→        method: "POST",
 39→        headers: { "Content-Type": "application/json" },
 40→        body: JSON.stringify({
 41→          humanAddress: walletAddress,
 42→          agentName: "OpenClaw Lending Agent",
 43→        }),
 44→      });
 45→
 46→      const data = await res.json();
 47→      if (data.error) throw new Error(data.error);
 48→
 49→      setSession(data);
 50→      setStatus("waiting");
 51→    } catch (err) {
 52→      const message =
 53→        err instanceof Error ? err.message : "Registration failed";
 54→      setError(message);
 55→      setStatus("error");
 56→    }
 57→  }, [walletAddress]);
 58→
 59→  // Auto-start registration on mount
 60→  useEffect(() => {
 61→    if (walletAddress && status === "idle") {
 62→      startRegistration();
 63→    }
 64→  }, [walletAddress, status, startRegistration]);
 65→
 66→  // Poll for completion — uses server-side session tracking with rolling tokens
 67→  useEffect(() => {
 68→    if (status !== "waiting" || !session) return;
 69→
 70→    const poll = async () => {
 71→      try {
 72→        const res = await fetch(
 73→          `/api/agent-id/register?key=${encodeURIComponent(session.sessionKey)}`
 74→        );
 75→        const data = await res.json();
 76→
