async function requestRegistration(opts) {
    const base = resolveApiBase(opts.apiBase);
    const network = opts.network ?? "mainnet";
    const payload = {
        mode: opts.mode,
        network,
        disclosures: opts.disclosures,
        humanAddress: opts.humanAddress,
        agentName: opts.agentName,
        agentDescription: opts.agentDescription,
    };
    const data = await apiFetch(`${base}/api/agent/register`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
    });
    return buildRegistrationSession(data, base);
}
/**
 * Initiate agent deregistration through the Self Agent ID REST API.
 */
async function requestDeregistration(opts) {
    const base = resolveApiBase(opts.apiBase);
    const network = opts.network ?? "mainnet";
    const payload = {
        network,
        agentAddress: opts.agentAddress,
        disclosures: opts.disclosures,
    };
    const data = await apiFetch(`${base}/api/agent/deregister`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
    });
    return buildDeregistrationSession(data, base);
}
/**
 * Initiate a proof refresh for an existing agent through the Self Agent ID REST API.
 *
 * Returns a session object with a deep link for the human to scan in the Self app,
 * and a polling method to wait for the new proof to be recorded on-chain.
 */
async function requestProofRefresh(opts) {
    const base = resolveApiBase(opts.apiBase);
    const network = opts.network ?? "mainnet";
    const payload = {
        agentId: opts.agentId,
        network,
        disclosures: opts.disclosures,
    };
    const data = await apiFetch(`${base}/api/agent/refresh`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
    });
    return buildRefreshSession(data, base);
}
/**
 * Fetch agent info from the public query API.
 */
async function getAgentInfo(agentId, opts) {
    const base = resolveApiBase(opts?.apiBase);
    const network = opts?.network ?? "mainnet";
