 60→    privyAppSecret,
 61→    celoRpcUrl,
 62→    pimlicoApiKey,
 63→    lendingContractAddress,
 64→  } = req.body;
 65→
 66→  if (!agentName) {
 67→    res.status(400).json({ error: "agentName is required" });
 68→    return;
 69→  }
 70→
 71→  if (agents.has(agentName)) {
 72→    res.status(409).json({ error: "Agent already exists" });
 73→    return;
 74→  }
 75→
 76→  try {
 77→    // Create agent workspace
 78→    const workspaceDir = join(AGENTS_DIR, agentName);
 79→    const skillsDir = join(workspaceDir, "skills", "lending");
 80→    mkdirSync(skillsDir, { recursive: true });
 81→
 82→    // Write OpenClaw config
 83→    const openclawConfig = {
 84→      agents: {
 85→        defaults: { workspace: workspaceDir },
 86→        list: [{ id: agentName, default: true }],
 87→      },
 88→      models: {
 89→        default: "openai/gpt-4o-mini",
 90→      },
 91→    };
 92→
 93→    writeFileSync(
 94→      join(workspaceDir, "openclaw.json"),
 95→      JSON.stringify(openclawConfig, null, 2)
 96→    );
 97→
 98→    // Write lending skill
 99→    const lendingSkill = `---
100→name: lending
101→description: >
102→  Interact with the AgentMicrolending contract on Celo. Request loans, discover
103→  and fill open loan requests, repay loans, and mark defaults.
104→version: 2.0.0
105→---
106→
107→# Lending Skill
108→
109→You interact with the AgentMicrolending smart contract on Celo for peer-to-peer
110→lending between autonomous agents. All loans use native CELO.
111→
112→## Loan Lifecycle
113→1. Request: Publish a loan request with amount, repay amount, and deadline
114→2. Discovery: Scan for open requests via getOpenLoans()
115→3. Verification: Verify borrower's human-backed status (8004 SBT) on-chain
116→4. Fund: Send CELO to borrower through fundLoan()
117→5. Repay: Borrower repays principal + interest via repayLoan() before deadline
118→6. Default: If deadline passes without repayment, call claimDefaulted()
119→
120→## Identity Gate
121→Before filling a loan, verify the borrower's human wallet holds the 8004
122→soulbound NFT from Self.xyz at contract 0xaC3DF9ABf80d0F5c020C06B04Cced27763355944.
123→`;
124→
125→    writeFileSync(join(skillsDir, "SKILL.md"), lendingSkill);
126→
127→    // Create Privy wallet for the agent
128→    let walletAddress = "";
129→    let walletId = "";
130→
131→    if (privyAppId && privyAppSecret) {
132→      try {
133→        const { PrivyClient } = await import("@privy-io/node");
134→        const client = new PrivyClient({ appId: privyAppId, appSecret: privyAppSecret });
135→        const wallet = await client.wallets().create({
136→          chain_type: "ethereum",
137→        });
138→        walletAddress = wallet.address;
139→        walletId = wallet.id;
140→      } catch (err) {
141→        console.error(`[${agentName}] Privy wallet creation failed:`, err);
142→      }
143→    }
144→
145→    // Start OpenClaw gateway as child process
146→    const env = {
147→      ...process.env,
148→      AGENT_WALLET_ADDRESS: walletAddress,
149→      AGENT_WALLET_ID: walletId,
150→      PRIVY_APP_ID: privyAppId || "",
151→      PRIVY_APP_SECRET: privyAppSecret || "",
152→      CELO_RPC_URL: celoRpcUrl || "https://forno.celo.org",
153→      PIMLICO_API_KEY: pimlicoApiKey || process.env.PIMLICO_API_KEY || "",
154→      LENDING_CONTRACT_ADDRESS: lendingContractAddress || process.env.LENDING_CONTRACT_ADDRESS || "",
155→      OPENCLAW_HOME: workspaceDir,
156→    };
157→
158→    const child = spawn(
159→      "npx",
160→      [
161→        "openclaw",
162→        "gateway",
163→        "--config",
164→        join(workspaceDir, "openclaw.json"),
165→        "--verbose",
166→      ],
167→      {
168→        env,
169→        cwd: workspaceDir,
170→        stdio: ["ignore", "pipe", "pipe"],
171→      }
172→    );
173→
174→    const instance: AgentInstance = {
175→      name: agentName,
176→      process: child,
177→      config: openclawConfig,
178→      status: "starting",
179→      walletAddress,
180→      walletId,
181→      createdAt: new Date().toISOString(),
182→    };
183→
184→    child.stdout?.on("data", (data: Buffer) => {
185→      console.log(`[${agentName}] ${data.toString().trim()}`);
186→      if (instance.status === "starting") {
187→        instance.status = "running";
188→      }
189→    });
190→
191→    child.stderr?.on("data", (data: Buffer) => {
192→      console.error(`[${agentName}] ${data.toString().trim()}`);
193→    });
194→
195→    child.on("exit", (code) => {
196→      console.log(`[${agentName}] exited with code ${code}`);
197→      instance.status = code === 0 ? "stopped" : "error";
198→      instance.process = null;
199→    });
200→
201→    agents.set(agentName, instance);
202→
203→    // Mark as running after a short delay
204→    setTimeout(() => {
205→      if (instance.status === "starting") {
206→        instance.status = "running";
207→      }
208→    }, 5000);
209→
210→    res.json({
211→      agentId: agentName,
212→      walletAddress,
213→      walletId,
214→      status: "starting",
215→      workspace: workspaceDir,
216→    });
217→  } catch (err) {
218→    const message = err instanceof Error ? err.message : "Deploy failed";
219→    res.status(500).json({ error: message });
220→  }
221→});
222→
223→// Stop an agent
224→app.post("/agents/:name/stop", (req, res) => {
225→  const agent = agents.get(req.params.name);
226→  if (!agent) {
227→    res.status(404).json({ error: "Agent not found" });
228→    return;
229→  }
230→
231→  if (agent.process) {
232→    agent.process.kill("SIGTERM");
233→    agent.status = "stopped";
234→  }
235→
236→  res.json({ name: agent.name, status: "stopped" });
237→});
238→
239→app.listen(PORT, () => {
240→  console.log(`Lending agent runtime listening on port ${PORT}`);
241→  if (!existsSync(AGENTS_DIR)) {
242→    mkdirSync(AGENTS_DIR, { recursive: true });
243→  }
244→});
245→

