 22→    );
 23→  }
 24→
 25→  try {
 26→    const projectId = process.env.RAILWAY_PROJECT_ID;
 27→    if (!projectId) {
 28→      return NextResponse.json(
 29→        { error: "RAILWAY_PROJECT_ID is not configured" },
 30→        { status: 500 }
 31→      );
 32→    }
 33→
 34→    // 1. Create service from GitHub repo (name = agent name for uniqueness)
 35→    const repo = "builders-garden/synthesis-hack";
 36→    const { serviceId, environmentId } = await createService(
 37→      projectId,
 38→      body.agentName,
 39→      repo,
 40→      "main",
 41→      "apps/agent"
 42→    );
 43→
 44→    // 2. Set env vars (bulk, single API call)
 45→    const setupPassword = crypto.randomUUID().replace(/-/g, "").slice(0, 32);
 46→    const envVars: Record<string, string> = {
 47→      AGENT_NAME: body.agentName,
 48→      SETUP_PASSWORD: setupPassword,
 49→      CELO_RPC_URL: process.env.CELO_RPC_URL || "https://forno.celo.org",
 50→    };
 51→
 52→    // Privy: pass through from server env for agent wallet creation
 53→    const privyAppId = process.env.PRIVY_APP_ID;
 54→    const privyAppSecret = process.env.PRIVY_APP_SECRET;
 55→    if (privyAppId) {
 56→      envVars.PRIVY_APP_ID = privyAppId;
 57→    }
 58→    if (privyAppSecret) {
 59→      envVars.PRIVY_APP_SECRET = privyAppSecret;
 60→    }
 61→
 62→    // Pimlico: pass through for gasless transactions
 63→    const pimlicoApiKey = process.env.PIMLICO_API_KEY;
 64→    if (pimlicoApiKey) {
 65→      envVars.PIMLICO_API_KEY = pimlicoApiKey;
 66→    }
 67→
 68→    // Lending contract address
 69→    const lendingContract = process.env.LENDING_CONTRACT_ADDRESS;
 70→    if (lendingContract) {
 71→      envVars.LENDING_CONTRACT_ADDRESS = lendingContract;
 72→    }
 73→
 74→    // Telegram: use frontend values, fall back to server env vars, skip if neither
 75→    const telegramToken = body.telegramBotToken || process.env.TELEGRAM_BOT_TOKEN;
 76→    const telegramUsers = body.telegramAllowedUsers || process.env.TELEGRAM_ALLOWED_USERS;
 77→    if (telegramToken) {
 78→      envVars.TELEGRAM_BOT_TOKEN = telegramToken;
 79→    }
 80→    if (telegramUsers) {
 81→      envVars.TELEGRAM_ALLOWED_USERS = telegramUsers;
 82→    }
 83→
 84→    await setEnvVars(projectId, serviceId, environmentId, envVars);
 85→
 86→    // 3. Create persistent volume
 87→    await createVolume(projectId, serviceId, environmentId, "/data");
 88→
 89→    // 4. Generate public domain
 90→    const domain = await createDomain(serviceId, environmentId);
 91→
 92→    // Railway auto-deploys when service is created with a linked repo + env vars set
 93→
 94→    return NextResponse.json({
 95→      projectId,
 96→      serviceId,
 97→      environmentId,
 98→      domain: `https://${domain}`,
 99→      setupPassword,
100→      status: "deploying",
101→    });
102→  } catch (err) {
103→    const message = err instanceof Error ? err.message : "Deploy failed";
104→    console.error("Railway deploy error:", message);
105→    return NextResponse.json({ error: message }, { status: 500 });
106→  }
