"use client";

import { useState } from "react";
import { useAccount, useSendTransaction, useWriteContract } from "wagmi";
import { parseEther } from "viem";
import { SelfVerification } from "@/components/self-verification";
import { LendingDashboard } from "@/components/lending-dashboard";

// Self Agent Registry on Celo mainnet
const REGISTRY_ADDRESS = "0x62E37d0f6c5f67784b8828B3dF68BCDbB2e55095" as const;

const REGISTRY_ABI = [
  {
    name: "setAgentWallet",
    type: "function",
    stateMutability: "nonpayable",
    inputs: [
      { name: "agentId", type: "uint256" },
      { name: "newWallet", type: "address" },
      { name: "deadline", type: "uint256" },
      { name: "signature", type: "bytes" },
    ],
    outputs: [],
  },
] as const;

const STEPS = [
  { id: "deploy", label: "Deploy Agent" },
  { id: "verify", label: "Verify Identity" },
  { id: "delegate", label: "Delegate" },
  { id: "fund", label: "Fund Agent" },
  { id: "monitor", label: "Monitor" },
] as const;

type Step = (typeof STEPS)[number]["id"];

const labelClass =
  "font-mono text-xs uppercase tracking-[0.15em] text-ink-lighter";
const inputClass =
  "w-full border-b border-cream-dark bg-transparent px-0 py-2 text-sm text-ink placeholder:text-ink-lighter focus:border-ink focus:outline-none";

export function DeployAgent() {
  const { address } = useAccount();
  const { sendTransactionAsync } = useSendTransaction();
  const { writeContractAsync } = useWriteContract();
  const [step, setStep] = useState<Step>("deploy");
  const [isVerified, setIsVerified] = useState(false);
  const [isDelegated, setIsDelegated] = useState(false);
  const [agentAddress, setAgentAddress] = useState<string | null>(null);
  const [walletId, setWalletId] = useState<string | null>(null);
  const [walletAddress, setWalletAddress] = useState<string | null>(null);
  const [smartAccountAddress, setSmartAccountAddress] = useState<string | null>(
    null
  );
  const [agentId, setAgentId] = useState<number | null>(null);
  const [deploying, setDeploying] = useState(false);
  const [delegating, setDelegating] = useState(false);
  const [agentName, setAgentName] = useState("");
  const [fundAmount, setFundAmount] = useState("");
  const [funding, setFunding] = useState(false);
  const [funded, setFunded] = useState(false);

  const handleDeploy = async () => {
    if (!agentName.trim()) return;
    setDeploying(true);
    try {
      const res = await fetch("/api/agent/deploy", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ agentName: agentName.trim() }),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);

      setWalletId(data.walletId);
      setWalletAddress(data.walletAddress);
      setSmartAccountAddress(data.smartAccountAddress);
      // The agent's operational address is the smart account
      setAgentAddress(data.smartAccountAddress || data.walletAddress);
      setStep("verify");
    } catch (err) {
      console.error("Deploy failed:", err);
    } finally {
      setDeploying(false);
    }
  };

  const handleVerificationSuccess = (
    _agentAddr: string,
    selfAgentId?: number
  ) => {
    setIsVerified(true);
    if (selfAgentId != null) {
      setAgentId(selfAgentId);
    }
    setStep("delegate");
  };

  const handleDelegate = async () => {
    if (!address || agentId == null || !walletId || !walletAddress) return;
    setDelegating(true);
    try {
      // 1. Backend signs EIP-712 with Privy agent wallet
      const res = await fetch("/api/agent-id/delegate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          agentId,
          walletId,
          walletAddress,
          ownerAddress: address,
        }),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);

      // 2. Human submits setAgentWallet tx on the Self registry
      await writeContractAsync({
        address: REGISTRY_ADDRESS,
        abi: REGISTRY_ABI,
        functionName: "setAgentWallet",
        args: [
          BigInt(agentId),
          data.newWallet as `0x${string}`,
          BigInt(data.deadline),
          data.signature as `0x${string}`,
        ],
      });

      setIsDelegated(true);
      setStep("fund");
    } catch (err) {
      console.error("Delegation failed:", err);
    } finally {
      setDelegating(false);
    }
  };

  const handleFund = async () => {
    if (!agentAddress || !fundAmount) return;
    const amount = parseFloat(fundAmount);
    if (!amount || amount <= 0) return;

    setFunding(true);
    try {
      await sendTransactionAsync({
        to: agentAddress as `0x${string}`,
        value: parseEther(fundAmount),
      });
      setFunded(true);
      setStep("monitor");
    } catch (err) {
      console.error("Funding failed:", err);
    } finally {
      setFunding(false);
    }
