import { createPublicClient, http, type LocalAccount } from "viem";
import { entryPoint07Address } from "viem/account-abstraction";
import { celo } from "viem/chains";
import { toSafeSmartAccount } from "permissionless/accounts";

const CELO_RPC_URL = process.env.CELO_RPC_URL || "https://forno.celo.org";

/**
 * Deterministically compute the Safe smart account address for a given EOA owner.
 * This does NOT deploy the account — it just predicts the counterfactual address.
 */
export async function getSmartAccountAddress(
  ownerAddress: `0x${string}`
): Promise<string> {
  const publicClient = createPublicClient({
    chain: celo,
    transport: http(CELO_RPC_URL),
  });

  // Stub owner — only the .address matters for counterfactual address computation.
  // Safe's CREATE2 address depends on owner address + entrypoint + version, not signatures.
  const stubOwner: LocalAccount = {
    address: ownerAddress,
    type: "local",
    source: "custom",
    publicKey: `0x${"00".repeat(64)}` as `0x${string}`,
    signMessage: async () => "0x" as `0x${string}`,
    signTypedData: async () => "0x" as `0x${string}`,
    signTransaction: async () => "0x" as `0x${string}`,
  };

  const account = await toSafeSmartAccount({
    client: publicClient,
    owners: [stubOwner],
    entryPoint: {
      address: entryPoint07Address,
      version: "0.7",
    },
    version: "1.4.1",
  });

  return account.address;
}

